const less = require('/workspace/less.js/packages/less');

const cases = [
  {
    name: 'comma-separated print and breakpoint',
    input: `@media print, (max-width: 992px) {\n  .main-view { display: flex; }\n}`,
    expectedIncludes: '@media print, (max-width: 992px)',
    forbidden: ['print(']
  },
  {
    name: 'comma-separated print and variable breakpoint',
    input: `@bp: (max-width: 992px);\n@media print, @bp {\n  .main-view { display: flex; }\n}`,
    expectedIncludes: '@media print, (max-width: 992px)',
    forbidden: ['print(']
  },
  {
    name: 'nested print with breakpoint still uses and',
    input: `@media print {\n  @media (max-width: 992px) {\n    .main-view { display: flex; }\n  }\n}`,
    expectedIncludes: '@media print and (max-width: 992px)',
    forbidden: ['print,', 'print(']
  },
  {
    name: 'function-like container style query remains compact',
    input: `@container style(--responsive) {\n  .main-view { display: flex; }\n}`,
    expectedIncludes: '@container style(--responsive)',
    forbidden: ['style (--responsive)']
  }
];

(async () => {
  let failures = 0;
  for (const testCase of cases) {
    const result = await less.render(testCase.input);
    const css = result.css.trim();
    console.log(`--- ${testCase.name} ---`);
    console.log(css);
    if (!css.includes(testCase.expectedIncludes)) {
      console.error(`Expected CSS to include: ${testCase.expectedIncludes}`);
      failures++;
    }
    for (const forbidden of testCase.forbidden || []) {
      if (css.includes(forbidden)) {
        console.error(`Forbidden CSS emitted: ${forbidden}`);
        failures++;
      }
    }
  }
  process.exitCode = failures ? 1 : 0;
})().catch(error => {
  console.error(error);
  process.exit(1);
});
